import React, { useState, useEffect, useRef } from 'react';
import { Mic, MicOff, Send, Pause, Play, Volume2, VolumeX, User, Bot, MessageSquare, FileText, BookOpen, Bookmark, Search, ZoomIn, ZoomOut, RotateCw, Download, Upload, Speaker, PlayCircle, Square, X, ChevronLeft, ChevronRight, Plus, Filter, Eye, Edit, Trash2, Award, Shield, Scale, Gavel, Book } from 'lucide-react';

interface Message {
  id: number;
  sender: 'user' | 'ai' | 'system';
  content: string;
  timestamp: Date;
  voiceUrl?: string; // URL for voice recording
  isPlaying?: boolean; // Whether voice is currently playing
}

interface Document {
  _id: string;
  name: string;
  type: 'contract' | 'evidence' | 'pleading' | 'correspondence' | 'case_file';
  pages: number;
  bookmarks?: BookmarkItem[];
  currentPage?: number;
}

interface BookmarkItem {
  id: string;
  page: number;
  label: string;
  note?: string;
}

interface VirtualBook {
  id: string;
  title: string;
  pages: number;
  currentPage: number;
  bookmarks: BookmarkItem[];
  content: string[];
}

interface EvidenceItem {
  id: string;
  name: string;
  type: 'digital' | 'physical' | 'document';
  description: string;
  dateAdded: string;
  fileSize: string;
  tags: string[];
  caseId: string;
  analysis?: {
    keyFindings: string[];
    relevance: string;
    reliability: string;
    notes: string;
  };
}

interface PaperworkTemplate {
  id: string;
  name: string;
  type: 'form' | 'document' | 'log';
  description: string;
  fields: string[];
}

interface Character {
  id: string;
  name: string;
  role: 'judge' | 'plaintiff' | 'defendant' | 'witness' | 'lawyer';
  avatar: string;
  bio: string;
  traits: string[];
  visualCues: {
    color: string;
    icon: string;
  };
}

const CourtroomSimulation: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputMessage, setInputMessage] = useState('');
  const [isRecording, setIsRecording] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [activeTab, setActiveTab] = useState<'chat' | 'documents' | 'notes' | 'evidence'>('chat');
  const [documents, setDocuments] = useState<Document[]>([]);
  const [virtualBooks, setVirtualBooks] = useState<VirtualBook[]>([]);
  const [selectedDocument, setSelectedDocument] = useState<Document | null>(null);
  const [selectedBook, setSelectedBook] = useState<VirtualBook | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [zoomLevel, setZoomLevel] = useState(100);
  const [bookmarks, setBookmarks] = useState<BookmarkItem[]>([]);
  const [isPlaying, setIsPlaying] = useState<number | null>(null); // ID of message currently playing
  const [mediaRecorder, setMediaRecorder] = useState<MediaRecorder | null>(null);
  const [audioChunks, setAudioChunks] = useState<Blob[]>([]);
  const [voicePlaying, setVoicePlaying] = useState<{[key: number]: boolean}>({});
  const [evidenceItems, setEvidenceItems] = useState<EvidenceItem[]>([]);
  const [paperworkTemplates, setPaperworkTemplates] = useState<PaperworkTemplate[]>([]);
  const [selectedEvidence, setSelectedEvidence] = useState<EvidenceItem | null>(null);
  const [showAddEvidence, setShowAddEvidence] = useState(false);
  const [characters, setCharacters] = useState<Character[]>([]);
  const [showCharacterPanel, setShowCharacterPanel] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Auto-scroll to bottom of messages
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  // Initialize media recorder for voice input
  useEffect(() => {
    const initMediaRecorder = async () => {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        const recorder = new MediaRecorder(stream);
        recorder.ondataavailable = (event) => {
          if (event.data.size > 0) {
            setAudioChunks((prev) => [...prev, event.data]);
          }
        };
        recorder.onstop = () => {
          const audioBlob = new Blob(audioChunks, { type: 'audio/webm' });
          // In a real implementation, you would send this to your backend
          console.log('Audio recorded:', audioBlob);
          setAudioChunks([]);
        };
        setMediaRecorder(recorder);
      } catch (err) {
        console.error('Error accessing microphone:', err);
      }
    };

    initMediaRecorder();
  }, []);

  // Fetch documents from backend
  useEffect(() => {
    const fetchDocuments = async () => {
      try {
        setLoading(true);
        
        // Fetch real documents from backend API
        const response = await fetch('http://localhost:5000/api/courtroom/documents');
        const data = await response.json();
        
        if (data.success) {
          setDocuments(data.data);
        } else {
          setError('Failed to fetch documents: ' + data.message);
        }
        
        setLoading(false);
      } catch (err) {
        setError('Error fetching documents: ' + (err as Error).message);
        console.error('Error fetching documents:', err);
        setLoading(false);
      }
    };

    fetchDocuments();
  }, []);

  // Fetch evidence items from backend
  useEffect(() => {
    const fetchEvidence = async () => {
      try {
        const response = await fetch('http://localhost:5000/api/evidence');
        const data = await response.json();
        
        if (data.success) {
          setEvidenceItems(data.data);
        }
      } catch (err) {
        console.error('Error fetching evidence:', err);
      }
    };

    fetchEvidence();
  }, []);

  // Fetch paperwork templates from backend
  useEffect(() => {
    const fetchPaperworkTemplates = async () => {
      try {
        const response = await fetch('http://localhost:5000/api/evidence/paperwork/templates');
        const data = await response.json();
        
        if (data.success) {
          setPaperworkTemplates(data.data);
        }
      } catch (err) {
        console.error('Error fetching paperwork templates:', err);
      }
    };

    fetchPaperworkTemplates();
  }, []);

  // Initialize characters
  useEffect(() => {
    // Sample characters for demonstration
    const sampleCharacters: Character[] = [
      {
        id: 'judge-sharma',
        name: 'Hon. Judge Sharma',
        role: 'judge',
        avatar: 'judge',
        bio: 'Experienced judge known for fairness and deep understanding of legal principles. Often references philosophical texts during proceedings.',
        traits: ['Wise', 'Fair', 'Philosophical', 'Authoritative'],
        visualCues: {
          color: 'from-amber-700 to-amber-900',
          icon: 'Gavel'
        }
      },
      {
        id: 'rajesh-kumar',
        name: 'Rajesh Kumar',
        role: 'plaintiff',
        avatar: 'plaintiff',
        bio: 'Sales executive accused of theft. Maintains innocence and references the Bhagavad Gita to affirm his commitment to truth and duty.',
        traits: ['Honest', 'Determined', 'Spiritual', 'Wrongly Accused'],
        visualCues: {
          color: 'from-blue-600 to-blue-800',
          icon: 'Shield'
        }
      },
      {
        id: 'prakash-mehta',
        name: 'Prakash Mehta',
        role: 'witness',
        avatar: 'witness',
        bio: 'Colleague of the plaintiff who was present during the inventory. Provides crucial testimony about the events.',
        traits: ['Observant', 'Loyal', 'Cautious', 'Truthful'],
        visualCues: {
          color: 'from-green-600 to-green-800',
          icon: 'Eye'
        }
      },
      {
        id: 'defense-lawyer',
        name: 'Defense Lawyer',
        role: 'lawyer',
        avatar: 'lawyer',
        bio: 'Skilled defense attorney representing the plaintiff. Known for meticulous examination of evidence and legal precedents.',
        traits: ['Analytical', 'Persuasive', 'Thorough', 'Strategic'],
        visualCues: {
          color: 'from-purple-600 to-purple-800',
          icon: 'Scale'
        }
      }
    ];
    
    setCharacters(sampleCharacters);
  }, []);

  // Initialize virtual books
  useEffect(() => {
    // Sample virtual books for demonstration
    const sampleBooks: VirtualBook[] = [
      {
        id: 'bhagavad-gita',
        title: 'Bhagavad Gita',
        pages: 100,
        currentPage: 1,
        bookmarks: [
          { id: '1', page: 25, label: 'Duty and Responsibility', note: 'Relevant to case oath' },
          { id: '2', page: 42, label: 'Truth and Honesty', note: 'Witness testimony principles' }
        ],
        content: Array(100).fill('').map((_, i) => `Page ${i+1} content would be displayed here.`)
      },
      {
        id: 'legal-handbook',
        title: 'Legal Practitioner Handbook',
        pages: 200,
        currentPage: 1,
        bookmarks: [
          { id: '3', page: 15, label: 'Courtroom Etiquette', note: 'Proper conduct guidelines' },
          { id: '4', page: 78, label: 'Evidence Presentation', note: 'How to present evidence effectively' }
        ],
        content: Array(200).fill('').map((_, i) => `Page ${i+1} content would be displayed here.`)
      }
    ];
    
    setVirtualBooks(sampleBooks);
  }, []);

  // Fetch initial messages from backend
  useEffect(() => {
    const fetchInitialMessages = async () => {
      try {
        const response = await fetch('http://localhost:5000/api/courtroom/messages');
        const data = await response.json();
        
        if (data.success) {
          setMessages(data.data);
        } else {
          // Set default messages if fetch fails
          setMessages([
            {
              id: 1,
              sender: 'system',
              content: 'Welcome to the CourtCraft courtroom simulation. You are representing the plaintiff in a contract dispute case.',
              timestamp: new Date()
            },
            {
              id: 2,
              sender: 'ai',
              content: 'Good morning, Counsel. I am Judge Sharma presiding over this matter. Please present your opening statement.',
              timestamp: new Date()
            }
          ]);
        }
      } catch (err) {
        console.error('Error fetching initial messages:', err);
        // Set default messages if fetch fails
        setMessages([
          {
            id: 1,
            sender: 'system',
            content: 'Welcome to the CourtCraft courtroom simulation. You are representing the plaintiff in a contract dispute case.',
            timestamp: new Date()
          },
          {
            id: 2,
            sender: 'ai',
            content: 'Good morning, Counsel. I am Judge Sharma presiding over this matter. Please present your opening statement.',
            timestamp: new Date()
          }
        ]);
      }
    };

    fetchInitialMessages();
  }, []);

  const handleSendMessage = async () => {
    if (inputMessage.trim() === '') return;
    
    const newMessage: Message = {
      id: messages.length + 1,
      sender: 'user',
      content: inputMessage,
      timestamp: new Date()
    };
    
    setMessages([...messages, newMessage]);
    setInputMessage('');
    
    // Send message to backend and get AI response
    try {
      const response = await fetch('http://localhost:5000/api/courtroom/respond', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ message: inputMessage })
      });
      
      const data = await response.json();
      
      if (data.success) {
        setMessages(prev => [...prev, {...data.data, isPlaying: false}]);
      } else {
        // Fallback AI response if backend fails
        setTimeout(() => {
          const aiResponse: Message = {
            id: messages.length + 2,
            sender: 'ai',
            content: "Thank you for that statement, Counsel. The defendant would like to respond to your claims. Mr. Advocate for the defense, please present your counter-argument.",
            timestamp: new Date(),
            isPlaying: false
          };
          setMessages(prev => [...prev, aiResponse]);
        }, 2000);
      }
    } catch (err) {
      console.error('Error sending message:', err);
      // Fallback AI response if backend fails
      setTimeout(() => {
        const aiResponse: Message = {
          id: messages.length + 2,
          sender: 'ai',
          content: "Thank you for that statement, Counsel. The defendant would like to respond to your claims. Mr. Advocate for the defense, please present your counter-argument.",
          timestamp: new Date(),
          isPlaying: false
        };
        setMessages(prev => [...prev, aiResponse]);
      }, 2000);
    }
  };

  const toggleRecording = () => {
    if (isRecording) {
      // Stop recording
      if (mediaRecorder && mediaRecorder.state !== 'inactive') {
        mediaRecorder.stop();
      }
      setIsRecording(false);
    } else {
      // Start recording
      if (mediaRecorder && mediaRecorder.state === 'inactive') {
        setAudioChunks([]);
        mediaRecorder.start();
        setIsRecording(true);
      }
    }
  };

  const toggleMute = () => {
    setIsMuted(!isMuted);
  };

  const getDocumentIcon = (type: string) => {
    switch (type) {
      case 'contract': return <FileText className="w-5 h-5 text-blue-500" />;
      case 'evidence': return <FileText className="w-5 h-5 text-green-500" />;
      case 'pleading': return <FileText className="w-5 h-5 text-purple-500" />;
      case 'correspondence': return <FileText className="w-5 h-5 text-yellow-500" />;
      case 'case_file': return <FileText className="w-5 h-5 text-red-500" />;
      default: return <FileText className="w-5 h-5 text-gray-500" />;
    }
  };

  const getEvidenceIcon = (type: string) => {
    switch (type) {
      case 'digital': return <FileText className="w-5 h-5 text-blue-500" />;
      case 'physical': return <FileText className="w-5 h-5 text-amber-600" />;
      case 'document': return <FileText className="w-5 h-5 text-green-500" />;
      default: return <FileText className="w-5 h-5 text-gray-500" />;
    }
  };

  const getCharacterIcon = (iconName: string) => {
    switch (iconName) {
      case 'Gavel': return <Gavel className="w-5 h-5" />;
      case 'Shield': return <Shield className="w-5 h-5" />;
      case 'Eye': return <Eye className="w-5 h-5" />;
      case 'Scale': return <Scale className="w-5 h-5" />;
      case 'Book': return <Book className="w-5 h-5" />;
      case 'Award': return <Award className="w-5 h-5" />;
      default: return <User className="w-5 h-5" />;
    }
  };

  const handleDocumentSelect = (doc: Document) => {
    setSelectedDocument(doc);
    setActiveTab('documents');
  };

  const handleBookSelect = (book: VirtualBook) => {
    setSelectedBook(book);
    setActiveTab('documents');
  };

  const handleEvidenceSelect = (evidence: EvidenceItem) => {
    setSelectedEvidence(evidence);
    setActiveTab('evidence');
  };

  const handlePageChange = (newPage: number) => {
    if (selectedBook) {
      const updatedBook = {
        ...selectedBook,
        currentPage: Math.max(1, Math.min(selectedBook.pages, newPage))
      };
      setSelectedBook(updatedBook);
      
      // Update in virtual books array
      setVirtualBooks(prev => 
        prev.map(b => b.id === selectedBook.id ? updatedBook : b)
      );
    }
  };

  const handleZoomIn = () => {
    setZoomLevel(prev => Math.min(prev + 25, 200));
  };

  const handleZoomOut = () => {
    setZoomLevel(prev => Math.max(prev - 25, 50));
  };

  const handleAddBookmark = () => {
    if (selectedBook) {
      const newBookmark: BookmarkItem = {
        id: Date.now().toString(),
        page: selectedBook.currentPage,
        label: `Bookmark ${selectedBook.bookmarks.length + 1}`,
        note: ''
      };
      
      const updatedBook = {
        ...selectedBook,
        bookmarks: [...selectedBook.bookmarks, newBookmark]
      };
      
      setSelectedBook(updatedBook);
      setVirtualBooks(prev => 
        prev.map(b => b.id === selectedBook.id ? updatedBook : b)
      );
    }
  };

  const handleRemoveBookmark = (bookmarkId: string) => {
    if (selectedBook) {
      const updatedBook = {
        ...selectedBook,
        bookmarks: selectedBook.bookmarks.filter(b => b.id !== bookmarkId)
      };
      
      setSelectedBook(updatedBook);
      setVirtualBooks(prev => 
        prev.map(b => b.id === selectedBook.id ? updatedBook : b)
      );
    }
  };

  const playVoice = (messageId: number) => {
    // In a real implementation, this would play the actual voice recording
    // For now, we'll just simulate playing
    setVoicePlaying(prev => ({ ...prev, [messageId]: true }));
    
    // Simulate voice playing for 3 seconds
    setTimeout(() => {
      setVoicePlaying(prev => ({ ...prev, [messageId]: false }));
    }, 3000);
  };

  const stopVoice = (messageId: number) => {
    setVoicePlaying(prev => ({ ...prev, [messageId]: false }));
  };

  const handleAddEvidence = async (evidenceData: any) => {
    try {
      const response = await fetch('http://localhost:5000/api/evidence/upload', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(evidenceData)
      });
      
      const data = await response.json();
      
      if (data.success) {
        setEvidenceItems(prev => [...prev, data.data]);
        setShowAddEvidence(false);
      }
    } catch (err) {
      console.error('Error adding evidence:', err);
    }
  };

  const getCharacterById = (id: string) => {
    return characters.find(character => character.id === id);
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="inline-block animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-indigo-600 mb-4"></div>
          <p className="text-gray-600">Loading courtroom simulation...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center py-12">
          <div className="bg-red-100 rounded-full w-16 h-16 flex items-center justify-center mx-auto mb-4">
            <svg className="w-8 h-8 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path>
            </svg>
          </div>
          <h3 className="text-xl font-bold text-gray-900 mb-2">Error Loading Courtroom Simulation</h3>
          <p className="text-gray-600 mb-4">{error}</p>
          <button 
            className="bg-indigo-600 text-white px-6 py-3 rounded-lg hover:bg-indigo-700 transition duration-300 font-medium"
            onClick={() => window.location.reload()}
          >
            Try Again
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Hidden audio element for playing voices */}
      <audio ref={audioRef} />
      
      {/* Header */}
      <div className="bg-white shadow-sm">
        <div className="container mx-auto px-4 py-4">
          <div className="flex justify-between items-center">
            <div>
              <h1 className="text-2xl font-bold text-gray-900">Contract Dispute Case</h1>
              <p className="text-gray-600">Plaintiff vs. Defendant - Civil Court, Delhi</p>
            </div>
            <div className="flex items-center space-x-4">
              <div className="flex items-center bg-red-100 text-red-800 px-3 py-1 rounded-full">
                <div className="w-2 h-2 bg-red-500 rounded-full mr-2 animate-pulse"></div>
                <span className="text-sm font-medium">Recording</span>
              </div>
              <button className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition duration-300">
                End Session
              </button>
            </div>
          </div>
        </div>
      </div>

      <div className="container mx-auto px-4 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
          {/* Main Courtroom Area */}
          <div className="lg:col-span-3">
            <div className="bg-white rounded-xl shadow-sm overflow-hidden">
              {/* Courtroom Visualization */}
              <div className="bg-gradient-to-b from-amber-800 to-amber-900 h-64 relative">
                <div className="absolute inset-0 flex items-center justify-center">
                  {/* Judge's Bench */}
                  <div className="bg-amber-700 w-64 h-24 rounded-lg flex items-center justify-center shadow-lg">
                    <div className="text-center">
                      <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center mx-auto mb-2">
                        <Gavel className="w-6 h-6 text-amber-800" />
                      </div>
                      <p className="text-white font-medium">Hon. Judge Sharma</p>
                      <p className="text-amber-200 text-sm">Presiding</p>
                    </div>
                  </div>
                  
                  {/* Plaintiff Table */}
                  <div className="absolute left-8 bottom-8 bg-amber-100 w-48 h-20 rounded-lg flex items-center justify-center shadow">
                    <div className="text-center">
                      <div className="w-8 h-8 bg-indigo-600 rounded-full flex items-center justify-center mx-auto mb-1">
                        <Shield className="w-4 h-4 text-white" />
                      </div>
                      <p className="text-gray-900 font-medium text-sm">You (Plaintiff)</p>
                    </div>
                  </div>
                  
                  {/* Defendant Table */}
                  <div className="absolute right-8 bottom-8 bg-amber-100 w-48 h-20 rounded-lg flex items-center justify-center shadow">
                    <div className="text-center">
                      <div className="w-8 h-8 bg-red-600 rounded-full flex items-center justify-center mx-auto mb-1">
                        <User className="w-4 h-4 text-white" />
                      </div>
                      <p className="text-gray-900 font-medium text-sm">Defendant</p>
                    </div>
                  </div>
                  
                  {/* Bhagavad Gita Reference Visualization */}
                  <div className="absolute top-4 right-4 bg-white bg-opacity-90 rounded-lg p-3 shadow-lg">
                    <div className="flex items-center">
                      <Book className="w-5 h-5 text-amber-700 mr-2" />
                      <span className="text-amber-800 text-sm font-medium">Bhagavad Gita Reference</span>
                    </div>
                    <p className="text-amber-700 text-xs mt-1">"Speak the truth, fulfill your duty"</p>
                  </div>
                </div>
              </div>
              
              {/* Chat Interface */}
              <div className="p-6">
                {/* Tabs */}
                <div className="flex border-b border-gray-200 mb-6">
                  <button
                    className={`pb-3 px-6 font-medium ${activeTab === 'chat' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-500'}`}
                    onClick={() => setActiveTab('chat')}
                  >
                    <MessageSquare className="w-5 h-5 inline mr-2" />
                    Courtroom Chat
                  </button>
                  <button
                    className={`pb-3 px-6 font-medium ${activeTab === 'documents' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-500'}`}
                    onClick={() => setActiveTab('documents')}
                  >
                    <FileText className="w-5 h-5 inline mr-2" />
                    Documents & Books
                  </button>
                  <button
                    className={`pb-3 px-6 font-medium ${activeTab === 'evidence' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-500'}`}
                    onClick={() => setActiveTab('evidence')}
                  >
                    <Search className="w-5 h-5 inline mr-2" />
                    Evidence
                  </button>
                  <button
                    className={`pb-3 px-6 font-medium ${activeTab === 'notes' ? 'text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-500'}`}
                    onClick={() => setActiveTab('notes')}
                  >
                    <BookOpen className="w-5 h-5 inline mr-2" />
                    Notes
                  </button>
                </div>
                
                {/* Chat Tab */}
                {activeTab === 'chat' && (
                  <div className="space-y-6">
                    {/* Messages */}
                    <div className="space-y-4 max-h-96 overflow-y-auto pr-2">
                      {messages.map(message => (
                        <div 
                          key={message.id} 
                          className={`flex ${message.sender === 'user' ? 'justify-end' : 'justify-start'}`}
                        >
                          <div 
                            className={`max-w-xs lg:max-w-md px-4 py-3 rounded-2xl ${
                              message.sender === 'user' 
                                ? 'bg-indigo-600 text-white rounded-br-none' 
                                : message.sender === 'ai'
                                  ? 'bg-gray-100 text-gray-900 rounded-bl-none'
                                  : 'bg-blue-100 text-blue-900 rounded-b-none'
                            }`}
                          >
                            <div className="flex justify-between items-start">
                              <p className="text-sm">{message.content}</p>
                              <button 
                                className="ml-2 text-white opacity-70 hover:opacity-100"
                                onClick={() => message.sender === 'user' ? playVoice(message.id) : playVoice(message.id)}
                              >
                                {voicePlaying[message.id] ? (
                                  <Square className="w-4 h-4" />
                                ) : (
                                  <Speaker className="w-4 h-4" />
                                )}
                              </button>
                            </div>
                            <p className={`text-xs mt-1 ${message.sender === 'user' ? 'text-indigo-200' : 'text-gray-500'}`}>
                              {message.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                            </p>
                          </div>
                        </div>
                      ))}
                      <div ref={messagesEndRef} />
                    </div>
                    
                    {/* Input Area */}
                    <div className="flex items-end space-x-3">
                      <div className="flex-1 relative">
                        <textarea
                          value={inputMessage}
                          onChange={(e) => setInputMessage(e.target.value)}
                          onKeyDown={(e) => {
                            if (e.key === 'Enter' && !e.shiftKey) {
                              e.preventDefault();
                              handleSendMessage();
                            }
                          }}
                          placeholder="Type your response..."
                          className="w-full px-4 py-3 border border-gray-300 rounded-2xl focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent resize-none"
                          rows={2}
                        />
                      </div>
                      <div className="flex space-x-2">
                        <button
                          onClick={toggleRecording}
                          className={`p-3 rounded-full ${
                            isRecording 
                              ? 'bg-red-100 text-red-600 hover:bg-red-200' 
                              : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                          } transition duration-200`}
                        >
                          {isRecording ? <MicOff className="w-5 h-5" /> : <Mic className="w-5 h-5" />}
                        </button>
                        <button
                          onClick={handleSendMessage}
                          disabled={inputMessage.trim() === ''}
                          className="p-3 bg-indigo-600 text-white rounded-full hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition duration-200"
                        >
                          <Send className="w-5 h-5" />
                        </button>
                      </div>
                    </div>
                  </div>
                )}
                
                {/* Documents & Books Tab */}
                {activeTab === 'documents' && (
                  <div className="space-y-6">
                    {/* Document Selection */}
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      {documents.map(doc => (
                        <div 
                          key={doc._id} 
                          className={`flex items-center p-4 border rounded-lg cursor-pointer transition duration-200 ${
                            selectedDocument?._id === doc._id 
                              ? 'border-indigo-500 bg-indigo-50' 
                              : 'border-gray-200 hover:bg-gray-50'
                          }`}
                          onClick={() => handleDocumentSelect(doc)}
                        >
                          <div className="mr-4">
                            {getDocumentIcon(doc.type)}
                          </div>
                          <div className="flex-1">
                            <h4 className="font-medium text-gray-900">{doc.name}</h4>
                            <p className="text-sm text-gray-500 capitalize">{doc.type} • {doc.pages} pages</p>
                          </div>
                          <button className="text-indigo-600 hover:text-indigo-800 font-medium">
                            View
                          </button>
                        </div>
                      ))}
                      
                      {virtualBooks.map(book => (
                        <div 
                          key={book.id} 
                          className={`flex items-center p-4 border rounded-lg cursor-pointer transition duration-200 ${
                            selectedBook?.id === book.id 
                              ? 'border-indigo-500 bg-indigo-50' 
                              : 'border-gray-200 hover:bg-gray-50'
                          }`}
                          onClick={() => handleBookSelect(book)}
                        >
                          <div className="mr-4">
                            <BookOpen className="w-5 h-5 text-amber-600" />
                          </div>
                          <div className="flex-1">
                            <h4 className="font-medium text-gray-900">{book.title}</h4>
                            <p className="text-sm text-gray-500">Virtual Book • {book.pages} pages</p>
                          </div>
                          <button className="text-indigo-600 hover:text-indigo-800 font-medium">
                            Open
                          </button>
                        </div>
                      ))}
                    </div>
                    
                    {/* Document Viewer */}
                    {selectedDocument && (
                      <div className="border border-gray-200 rounded-lg p-4">
                        <div className="flex justify-between items-center mb-4">
                          <h3 className="font-bold text-gray-900">{selectedDocument.name}</h3>
                          <div className="flex space-x-2">
                            <button className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200">
                              <Download className="w-4 h-4" />
                            </button>
                            <button className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200">
                              <Upload className="w-4 h-4" />
                            </button>
                          </div>
                        </div>
                        
                        <div className="bg-gray-100 border border-gray-300 rounded-lg h-96 flex items-center justify-center">
                          <div className="text-center">
                            <FileText className="w-12 h-12 text-gray-400 mx-auto mb-4" />
                            <p className="text-gray-500">Document viewer for {selectedDocument.name}</p>
                            <p className="text-sm text-gray-400 mt-2">PDF content would be displayed here</p>
                          </div>
                        </div>
                        
                        <div className="flex justify-between items-center mt-4">
                          <div className="text-sm text-gray-500">
                            Page 1 of {selectedDocument.pages}
                          </div>
                          <div className="flex space-x-2">
                            <button className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200">
                              <ZoomOut className="w-4 h-4" />
                            </button>
                            <span className="px-3 py-1 bg-gray-100 rounded-lg text-sm">100%</span>
                            <button className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200">
                              <ZoomIn className="w-4 h-4" />
                            </button>
                          </div>
                        </div>
                      </div>
                    )}
                    
                    {/* Virtual Book Viewer */}
                    {selectedBook && (
                      <div className="border border-gray-200 rounded-lg">
                        <div className="flex justify-between items-center p-4 border-b border-gray-200">
                          <h3 className="font-bold text-gray-900">{selectedBook.title}</h3>
                          <div className="flex space-x-2">
                            <button 
                              className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200"
                              onClick={handleAddBookmark}
                            >
                              <Bookmark className="w-4 h-4" />
                            </button>
                            <button className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200">
                              <Download className="w-4 h-4" />
                            </button>
                            <button className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200">
                              <Upload className="w-4 h-4" />
                            </button>
                          </div>
                        </div>
                        
                        <div className="flex">
                          {/* Bookmarks Sidebar */}
                          <div className="w-1/4 border-r border-gray-200 p-4">
                            <h4 className="font-medium text-gray-900 mb-3">Bookmarks</h4>
                            <div className="space-y-2">
                              {selectedBook.bookmarks.map(bookmark => (
                                <div 
                                  key={bookmark.id} 
                                  className="p-2 bg-gray-50 rounded-lg cursor-pointer hover:bg-gray-100"
                                  onClick={() => handlePageChange(bookmark.page)}
                                >
                                  <div className="flex justify-between">
                                    <span className="font-medium text-sm">{bookmark.label}</span>
                                    <button 
                                      className="text-gray-400 hover:text-red-500"
                                      onClick={(e) => {
                                        e.stopPropagation();
                                        handleRemoveBookmark(bookmark.id);
                                      }}
                                    >
                                      <X className="w-4 h-4" />
                                    </button>
                                  </div>
                                  <p className="text-xs text-gray-500">Page {bookmark.page}</p>
                                  {bookmark.note && (
                                    <p className="text-xs text-gray-600 mt-1">{bookmark.note}</p>
                                  )}
                                </div>
                              ))}
                            </div>
                            
                            {/* Bhagavad Gita Reference Section */}
                            {selectedBook.id === 'bhagavad-gita' && (
                              <div className="mt-6 p-3 bg-amber-50 border border-amber-200 rounded-lg">
                                <h5 className="font-medium text-amber-900 text-sm mb-2">Relevant Quotes</h5>
                                <p className="text-amber-800 text-xs italic">
                                  "You have a right to perform your prescribed duty, but not to the fruits of action."
                                </p>
                                <button 
                                  className="text-amber-700 text-xs mt-2 hover:text-amber-900"
                                  onClick={() => handlePageChange(25)}
                                >
                                  View context (Page 25)
                                </button>
                              </div>
                            )}
                          </div>
                          
                          {/* Book Content */}
                          <div className="flex-1">
                            <div className="p-4 border-b border-gray-200 flex justify-between items-center">
                              <div className="text-sm text-gray-500">
                                Page {selectedBook.currentPage} of {selectedBook.pages}
                              </div>
                              <div className="flex space-x-2">
                                <button 
                                  className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200"
                                  onClick={() => handlePageChange(selectedBook.currentPage - 1)}
                                  disabled={selectedBook.currentPage <= 1}
                                >
                                  <ChevronLeft className="w-4 h-4" />
                                </button>
                                <button 
                                  className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200"
                                  onClick={() => handlePageChange(selectedBook.currentPage + 1)}
                                  disabled={selectedBook.currentPage >= selectedBook.pages}
                                >
                                  <ChevronRight className="w-4 h-4" />
                                </button>
                                <button 
                                  className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200"
                                  onClick={handleZoomOut}
                                >
                                  <ZoomOut className="w-4 h-4" />
                                </button>
                                <span className="px-3 py-1 bg-gray-100 rounded-lg text-sm">{zoomLevel}%</span>
                                <button 
                                  className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200"
                                  onClick={handleZoomIn}
                                >
                                  <ZoomIn className="w-4 h-4" />
                                </button>
                                <button className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200">
                                  <RotateCw className="w-4 h-4" />
                                </button>
                              </div>
                            </div>
                            
                            <div 
                              className="p-8 h-96 overflow-y-auto"
                              style={{ zoom: `${zoomLevel}%` }}
                            >
                              <div className="prose max-w-none">
                                <h2 className="text-xl font-bold mb-4">Page {selectedBook.currentPage}</h2>
                                <p>{selectedBook.content[selectedBook.currentPage - 1]}</p>
                              </div>
                            </div>
                          </div>
                        </div>
                      </div>
                    )}
                  </div>
                )}
                
                {/* Evidence Tab */}
                {activeTab === 'evidence' && (
                  <div className="space-y-6">
                    {/* Evidence Header */}
                    <div className="flex justify-between items-center">
                      <h3 className="font-bold text-gray-900 text-lg">Digital Evidence & Paperwork</h3>
                      <button 
                        className="bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition duration-300 flex items-center"
                        onClick={() => setShowAddEvidence(true)}
                      >
                        <Plus className="w-4 h-4 mr-2" />
                        Add Evidence
                      </button>
                    </div>
                    
                    {/* Evidence Filters */}
                    <div className="flex space-x-2">
                      <button className="px-3 py-1 bg-indigo-100 text-indigo-800 rounded-full text-sm">All</button>
                      <button className="px-3 py-1 bg-gray-100 text-gray-800 rounded-full text-sm">Digital</button>
                      <button className="px-3 py-1 bg-gray-100 text-gray-800 rounded-full text-sm">Physical</button>
                      <button className="px-3 py-1 bg-gray-100 text-gray-800 rounded-full text-sm">Documents</button>
                    </div>
                    
                    {/* Evidence Grid */}
                    {!selectedEvidence ? (
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {evidenceItems.map(evidence => (
                          <div 
                            key={evidence.id} 
                            className="border border-gray-200 rounded-lg p-4 hover:bg-gray-50 cursor-pointer transition duration-200"
                            onClick={() => handleEvidenceSelect(evidence)}
                          >
                            <div className="flex items-start">
                              <div className="mr-3 mt-1">
                                {getEvidenceIcon(evidence.type)}
                              </div>
                              <div className="flex-1">
                                <div className="flex justify-between">
                                  <h4 className="font-medium text-gray-900">{evidence.name}</h4>
                                  <span className="text-xs text-gray-500">{evidence.fileSize}</span>
                                </div>
                                <p className="text-sm text-gray-600 mt-1">{evidence.description}</p>
                                <div className="flex flex-wrap gap-1 mt-2">
                                  {evidence.tags.map((tag, index) => (
                                    <span key={index} className="inline-block bg-gray-100 text-gray-800 text-xs px-2 py-1 rounded">
                                      {tag}
                                    </span>
                                  ))}
                                </div>
                                <div className="flex justify-between items-center mt-3">
                                  <span className="text-xs text-gray-500">
                                    Added: {new Date(evidence.dateAdded).toLocaleDateString()}
                                  </span>
                                  <div className="flex space-x-2">
                                    <button className="text-indigo-600 hover:text-indigo-800">
                                      <Eye className="w-4 h-4" />
                                    </button>
                                    <button className="text-gray-600 hover:text-gray-800">
                                      <Edit className="w-4 h-4" />
                                    </button>
                                    <button className="text-red-600 hover:text-red-800">
                                      <Trash2 className="w-4 h-4" />
                                    </button>
                                  </div>
                                </div>
                              </div>
                            </div>
                          </div>
                        ))}
                      </div>
                    ) : (
                      /* Evidence Detail View */
                      <div className="border border-gray-200 rounded-lg p-6">
                        <div className="flex justify-between items-start mb-6">
                          <div>
                            <h3 className="font-bold text-gray-900 text-xl">{selectedEvidence.name}</h3>
                            <div className="flex items-center mt-2">
                              <span className="inline-block bg-gray-100 text-gray-800 text-xs px-2 py-1 rounded mr-2">
                                {selectedEvidence.type}
                              </span>
                              <span className="text-sm text-gray-500">{selectedEvidence.fileSize}</span>
                            </div>
                          </div>
                          <button 
                            className="text-gray-500 hover:text-gray-700"
                            onClick={() => setSelectedEvidence(null)}
                          >
                            <X className="w-5 h-5" />
                          </button>
                        </div>
                        
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                          <div className="md:col-span-2">
                            <h4 className="font-medium text-gray-900 mb-3">Description</h4>
                            <p className="text-gray-700 mb-6">{selectedEvidence.description}</p>
                            
                            {selectedEvidence.analysis && (
                              <>
                                <h4 className="font-medium text-gray-900 mb-3">Analysis</h4>
                                <div className="bg-blue-50 border border-blue-200 rounded-lg p-4 mb-6">
                                  <h5 className="font-medium text-blue-900 mb-2">Key Findings</h5>
                                  <ul className="list-disc pl-5 space-y-1">
                                    {selectedEvidence.analysis.keyFindings.map((finding, index) => (
                                      <li key={index} className="text-blue-800 text-sm">{finding}</li>
                                    ))}
                                  </ul>
                                  
                                  <div className="grid grid-cols-2 gap-4 mt-4">
                                    <div>
                                      <p className="text-xs text-blue-700">Relevance</p>
                                      <p className="font-medium text-blue-900">{selectedEvidence.analysis.relevance}</p>
                                    </div>
                                    <div>
                                      <p className="text-xs text-blue-700">Reliability</p>
                                      <p className="font-medium text-blue-900">{selectedEvidence.analysis.reliability}</p>
                                    </div>
                                  </div>
                                  
                                  {selectedEvidence.analysis.notes && (
                                    <div className="mt-3">
                                      <p className="text-xs text-blue-700">Notes</p>
                                      <p className="text-blue-800 text-sm">{selectedEvidence.analysis.notes}</p>
                                    </div>
                                  )}
                                </div>
                              </>
                            )}
                            
                            <h4 className="font-medium text-gray-900 mb-3">Tags</h4>
                            <div className="flex flex-wrap gap-2 mb-6">
                              {selectedEvidence.tags.map((tag, index) => (
                                <span key={index} className="inline-block bg-gray-100 text-gray-800 text-sm px-3 py-1 rounded-full">
                                  {tag}
                                </span>
                              ))}
                            </div>
                          </div>
                          
                          <div>
                            <h4 className="font-medium text-gray-900 mb-3">Actions</h4>
                            <div className="space-y-3">
                              <button className="w-full bg-indigo-600 text-white py-2 rounded-lg hover:bg-indigo-700 transition duration-300 flex items-center justify-center">
                                <Download className="w-4 h-4 mr-2" />
                                Download
                              </button>
                              <button className="w-full bg-gray-100 text-gray-800 py-2 rounded-lg hover:bg-gray-200 transition duration-300 flex items-center justify-center">
                                <PlayCircle className="w-4 h-4 mr-2" />
                                Analyze with AI
                              </button>
                              <button className="w-full bg-gray-100 text-gray-800 py-2 rounded-lg hover:bg-gray-200 transition duration-300 flex items-center justify-center">
                                <FileText className="w-4 h-4 mr-2" />
                                Generate Paperwork
                              </button>
                            </div>
                            
                            <h4 className="font-medium text-gray-900 mt-6 mb-3">Paperwork Templates</h4>
                            <div className="space-y-2">
                              {paperworkTemplates.slice(0, 2).map(template => (
                                <div key={template.id} className="border border-gray-200 rounded-lg p-3 hover:bg-gray-50 cursor-pointer">
                                  <h5 className="font-medium text-gray-900 text-sm">{template.name}</h5>
                                  <p className="text-xs text-gray-600 mt-1">{template.description}</p>
                                </div>
                              ))}
                              <button className="text-indigo-600 text-sm hover:text-indigo-800">
                                View all templates
                              </button>
                            </div>
                          </div>
                        </div>
                      </div>
                    )}
                    
                    {/* Add Evidence Modal */}
                    {showAddEvidence && (
                      <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
                        <div className="bg-white rounded-lg w-full max-w-md">
                          <div className="p-6">
                            <div className="flex justify-between items-center mb-4">
                              <h3 className="font-bold text-gray-900">Add New Evidence</h3>
                              <button 
                                className="text-gray-500 hover:text-gray-700"
                                onClick={() => setShowAddEvidence(false)}
                              >
                                <X className="w-5 h-5" />
                              </button>
                            </div>
                            
                            <form onSubmit={(e) => {
                              e.preventDefault();
                              const formData = new FormData(e.target as HTMLFormElement);
                              handleAddEvidence({
                                name: formData.get('name'),
                                type: formData.get('type'),
                                description: formData.get('description'),
                                tags: (formData.get('tags') as string).split(',').map(tag => tag.trim()),
                                caseId: 'inventory-case-001'
                              });
                            }}>
                              <div className="space-y-4">
                                <div>
                                  <label className="block text-sm font-medium text-gray-700 mb-1">Evidence Name</label>
                                  <input 
                                    type="text" 
                                    name="name"
                                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                                    required
                                  />
                                </div>
                                
                                <div>
                                  <label className="block text-sm font-medium text-gray-700 mb-1">Type</label>
                                  <select 
                                    name="type"
                                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                                    required
                                  >
                                    <option value="digital">Digital Evidence</option>
                                    <option value="physical">Physical Evidence</option>
                                    <option value="document">Document</option>
                                  </select>
                                </div>
                                
                                <div>
                                  <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
                                  <textarea 
                                    name="description"
                                    rows={3}
                                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                                    required
                                  ></textarea>
                                </div>
                                
                                <div>
                                  <label className="block text-sm font-medium text-gray-700 mb-1">Tags (comma separated)</label>
                                  <input 
                                    type="text" 
                                    name="tags"
                                    placeholder="e.g., video, security, timestamp"
                                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                                  />
                                </div>
                              </div>
                              
                              <div className="flex justify-end space-x-3 mt-6">
                                <button 
                                  type="button"
                                  className="px-4 py-2 text-gray-700 hover:text-gray-900"
                                  onClick={() => setShowAddEvidence(false)}
                                >
                                  Cancel
                                </button>
                                <button 
                                  type="submit"
                                  className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700"
                                >
                                  Add Evidence
                                </button>
                              </div>
                            </form>
                          </div>
                        </div>
                      </div>
                    )}
                  </div>
                )}
                
                {/* Notes Tab */}
                {activeTab === 'notes' && (
                  <div className="space-y-4">
                    <textarea
                      placeholder="Take notes during your session..."
                      className="w-full h-64 px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent resize-none"
                    />
                    <div className="flex justify-end">
                      <button className="bg-indigo-600 text-white px-6 py-2 rounded-lg hover:bg-indigo-700 transition duration-300">
                        Save Notes
                      </button>
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
          
          {/* Sidebar */}
          <div className="space-y-6">
            {/* Controls */}
            <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-100">
              <h3 className="font-bold text-gray-900 mb-4">Courtroom Controls</h3>
              <div className="space-y-4">
                <button
                  onClick={toggleMute}
                  className="w-full flex items-center justify-center p-3 bg-gray-100 hover:bg-gray-200 rounded-lg transition duration-200"
                >
                  {isMuted ? <VolumeX className="w-5 h-5 mr-2" /> : <Volume2 className="w-5 h-5 mr-2" />}
                  {isMuted ? 'Unmute' : 'Mute'}
                </button>
                <button className="w-full flex items-center justify-center p-3 bg-gray-100 hover:bg-gray-200 rounded-lg transition duration-200">
                  <Pause className="w-5 h-5 mr-2" />
                  Pause Session
                </button>
                <button className="w-full flex items-center justify-center p-3 bg-indigo-600 text-white hover:bg-indigo-700 rounded-lg transition duration-300">
                  <Play className="w-5 h-5 mr-2" />
                  Resume Session
                </button>
              </div>
            </div>
            
            {/* Case Information */}
            <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-100">
              <h3 className="font-bold text-gray-900 mb-4">Case Information</h3>
              <div className="space-y-3">
                <div>
                  <p className="text-sm text-gray-500">Case Type</p>
                  <p className="font-medium">Contract Dispute</p>
                </div>
                <div>
                  <p className="text-sm text-gray-500">Parties</p>
                  <p className="font-medium">Plaintiff vs. Defendant</p>
                </div>
                <div>
                  <p className="text-sm text-gray-500">Filed On</p>
                  <p className="font-medium">October 15, 2025</p>
                </div>
                <div>
                  <p className="text-sm text-gray-500">Status</p>
                  <span className="inline-block bg-green-100 text-green-800 text-xs font-medium px-2.5 py-0.5 rounded-full">
                    In Progress
                  </span>
                </div>
              </div>
            </div>
            
            {/* Timer */}
            <div className="bg-gradient-to-br from-indigo-500 to-purple-600 rounded-xl shadow-sm p-6 text-white">
              <h3 className="font-bold mb-2">Session Timer</h3>
              <div className="text-3xl font-mono font-bold">24:18</div>
              <p className="text-indigo-100 text-sm mt-1">Time elapsed</p>
              <div className="mt-4 w-full bg-white bg-opacity-20 rounded-full h-2">
                <div className="bg-white h-2 rounded-full" style={{ width: '45%' }}></div>
              </div>
              <p className="text-indigo-100 text-xs mt-2">45% of allocated time used</p>
            </div>
            
            {/* Character Panel */}
            <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-100">
              <div className="flex justify-between items-center mb-4">
                <h3 className="font-bold text-gray-900">Characters</h3>
                <button 
                  className="text-indigo-600 hover:text-indigo-800"
                  onClick={() => setShowCharacterPanel(!showCharacterPanel)}
                >
                  {showCharacterPanel ? 'Hide' : 'Show'}
                </button>
              </div>
              
              {showCharacterPanel && (
                <div className="space-y-4">
                  {characters.map(character => (
                    <div 
                      key={character.id} 
                      className={`p-3 rounded-lg border-l-4 ${character.visualCues.color.replace('from-', 'border-').replace('to-', ' ')}`}
                    >
                      <div className="flex items-center">
                        <div className={`w-8 h-8 rounded-full bg-gradient-to-r ${character.visualCues.color} flex items-center justify-center mr-3`}>
                          {getCharacterIcon(character.visualCues.icon)}
                        </div>
                        <div>
                          <h4 className="font-medium text-gray-900">{character.name}</h4>
                          <p className="text-xs text-gray-600 capitalize">{character.role}</p>
                        </div>
                      </div>
                      
                      {character.id === 'rajesh-kumar' && (
                        <div className="mt-2 p-2 bg-amber-50 rounded-lg">
                          <p className="text-amber-800 text-xs italic">
                            "I solemnly swear to speak the truth, guided by the principles of the Bhagavad Gita."
                          </p>
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              )}
            </div>
            
            {/* Bhagavad Gita Reference */}
            <div className="bg-amber-50 border border-amber-200 rounded-xl shadow-sm p-6">
              <div className="flex items-center mb-3">
                <Book className="w-6 h-6 text-amber-700 mr-2" />
                <h3 className="font-bold text-amber-900">Spiritual Reference</h3>
              </div>
              <p className="text-amber-800 text-sm mb-3">
                "Remember the teachings from the Bhagavad Gita about duty and truth."
              </p>
              <button 
                className="text-amber-700 hover:text-amber-900 text-sm font-medium flex items-center"
                onClick={() => {
                  const gitaBook = virtualBooks.find(b => b.id === 'bhagavad-gita');
                  if (gitaBook) {
                    handleBookSelect(gitaBook);
                  }
                }}
              >
                <Bookmark className="w-4 h-4 mr-1" />
                Open Reference
              </button>
            </div>
            
            {/* Voice Controls */}
            <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-100">
              <h3 className="font-bold text-gray-900 mb-4">Voice Controls</h3>
              <div className="space-y-3">
                <div className="flex items-center justify-between">
                  <span className="text-sm text-gray-600">User Voice (Learned Counsel)</span>
                  <div className="flex space-x-2">
                    <button className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200">
                      <PlayCircle className="w-4 h-4 text-indigo-600" />
                    </button>
                    <button className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200">
                      <Square className="w-4 h-4 text-red-600" />
                    </button>
                  </div>
                </div>
                <div className="flex items-center justify-between">
                  <span className="text-sm text-gray-600">AI Voice (Hon'ble Court)</span>
                  <div className="flex space-x-2">
                    <button className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200">
                      <PlayCircle className="w-4 h-4 text-green-600" />
                    </button>
                    <button className="p-2 bg-gray-100 rounded-lg hover:bg-gray-200">
                      <Square className="w-4 h-4 text-red-600" />
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CourtroomSimulation;
